// ⚙️  KONFIGURASI TEST
const FITFLOW_BASE_URL  = 'http://localhost:3000';
const FONNTE_WEBHOOK_KEY = 'fitflow_wa_bot_2024'; // sama dgn .env.local
const DEVICE_PHONE       = '628xxxxxxxxx'; // nomor WA instruktur di Fonnte
const SENDER_PHONE       = '628yyyyyyyyyy'; // nomor pengirim (beda dari device)
const TEST_MESSAGE       = 'Kak ada kelas poundfit jam berapa ya?';
const SENDER_NAME        = 'Test User';
// ─────────────────────────────────────────────────────────

msg.url    = `${FITFLOW_BASE_URL}/api/wa/incoming?key=${FONNTE_WEBHOOK_KEY}`;
msg.method = 'POST';
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = JSON.stringify({
    device:  DEVICE_PHONE,
    sender:  SENDER_PHONE,
    message: TEST_MESSAGE,
    name:    SENDER_NAME,
    id:      'test_' + Date.now()
});
return msg;
